# --- plot helper (hidden) — the substitution key as a scattered mapping ---
# The scrambled-alphabet curve is built by running the student's OWN substitute
# on every letter. Falls back to reading the key directly until it works. The
# diagonal is a fixed comparison.
def __identity():
    return [[i, i] for i in range(26)]

def __map_ref(key):
    return [[i, ord(key[i]) - 97] for i in range(26)]

def __map_student(key):
    pts = []
    for i in range(26):
        landed = substitute(chr(97 + i), key)   # <- the STUDENT's function
        pts.append([i, ord(landed) - 97])
    return pts

def __plot(key):
    try:
        m = __map_student(key)
        if m and len(m) == 26:
            scr = {"name": "scrambled alphabet (your cipher)", "points": m, "highlight": True}
        else:
            raise ValueError()
    except Exception:
        scr = {"name": "scrambled alphabet (key)", "points": __map_ref(key), "highlight": True}
    return [scr, {"name": "no scramble (a=a, b=b, …)", "points": __identity(), "highlight": False}]
